import React, { useState } from 'react';
import axios from 'axios';

const styles = `
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'DM Sans', sans-serif;
    background: #0a0e1a;
    color: #e8eaf0;
    min-height: 100vh;
  }

  .app {
    max-width: 1100px;
    margin: 0 auto;
    padding: 40px 24px;
  }

  /* HEADER */
  .header {
    text-align: center;
    margin-bottom: 48px;
  }

  .header-tag {
    display: inline-block;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: #4ade80;
    background: rgba(74,222,128,0.08);
    border: 1px solid rgba(74,222,128,0.2);
    padding: 4px 14px;
    border-radius: 20px;
    margin-bottom: 16px;
  }

  .header h1 {
    font-family: 'DM Serif Display', serif;
    font-size: 42px;
    font-weight: 400;
    color: #fff;
    line-height: 1.1;
    margin-bottom: 10px;
  }

  .header h1 span {
    color: #4ade80;
  }

  .header p {
    color: #6b7280;
    font-size: 15px;
  }

  /* SEARCH */
  .search-box {
    background: #111827;
    border: 1px solid #1f2937;
    border-radius: 16px;
    padding: 28px 32px;
    margin-bottom: 40px;
    display: flex;
    gap: 12px;
    align-items: center;
  }

  .search-label {
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: #4b5563;
    white-space: nowrap;
  }

  .search-input {
    flex: 1;
    background: #0a0e1a;
    border: 1px solid #1f2937;
    border-radius: 10px;
    padding: 12px 18px;
    font-family: 'DM Sans', sans-serif;
    font-size: 15px;
    color: #e8eaf0;
    outline: none;
    transition: border-color 0.2s;
  }

  .search-input:focus {
    border-color: #4ade80;
  }

  .search-input::placeholder {
    color: #374151;
  }

  .search-btn {
    background: #4ade80;
    color: #0a0e1a;
    border: none;
    border-radius: 10px;
    padding: 12px 28px;
    font-family: 'DM Sans', sans-serif;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
    white-space: nowrap;
  }

  .search-btn:hover { background: #22c55e; }
  .search-btn:disabled { opacity: 0.5; cursor: not-allowed; }

  /* LOADING */
  .loading {
    text-align: center;
    padding: 60px;
    color: #4b5563;
  }

  .spinner {
    width: 36px;
    height: 36px;
    border: 3px solid #1f2937;
    border-top-color: #4ade80;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
    margin: 0 auto 16px;
  }

  @keyframes spin { to { transform: rotate(360deg); } }

  /* ERROR */
  .error-box {
    background: rgba(239,68,68,0.08);
    border: 1px solid rgba(239,68,68,0.2);
    border-radius: 12px;
    padding: 16px 20px;
    color: #f87171;
    margin-bottom: 24px;
  }

  /* REPORT */
  .company-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    margin-bottom: 32px;
    padding-bottom: 24px;
    border-bottom: 1px solid #1f2937;
  }

  .company-name {
    font-family: 'DM Serif Display', serif;
    font-size: 32px;
    color: #fff;
    margin-bottom: 4px;
  }

  .company-symbol {
    font-size: 13px;
    color: #4b5563;
    letter-spacing: 1px;
    font-weight: 500;
    text-transform: uppercase;
  }

  .cmp-badge {
    text-align: right;
  }

  .cmp-label {
    font-size: 11px;
    color: #4b5563;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 4px;
  }

  .cmp-value {
    font-family: 'DM Serif Display', serif;
    font-size: 36px;
    color: #4ade80;
  }

  /* SECTION */
  .section {
    margin-bottom: 32px;
  }

  .section-title {
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: #4ade80;
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .section-title::after {
    content: '';
    flex: 1;
    height: 1px;
    background: #1f2937;
  }

  /* STAT CARDS */
  .stat-cards {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 12px;
  }

  .stat-card {
    background: #111827;
    border: 1px solid #1f2937;
    border-radius: 12px;
    padding: 18px 20px;
    transition: border-color 0.2s;
  }

  .stat-card:hover { border-color: #374151; }

  .stat-label {
    font-size: 11px;
    color: #4b5563;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 8px;
  }

  .stat-value {
    font-size: 22px;
    font-weight: 600;
    color: #e8eaf0;
  }

  /* TABLE */
  .table-wrap {
    background: #111827;
    border: 1px solid #1f2937;
    border-radius: 12px;
    overflow: hidden;
  }

  table {
    width: 100%;
    border-collapse: collapse;
  }

  thead tr {
    background: #0d1117;
  }

  th {
    padding: 12px 18px;
    text-align: left;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: #4b5563;
    border-bottom: 1px solid #1f2937;
  }

  td {
    padding: 14px 18px;
    font-size: 14px;
    color: #d1d5db;
    border-bottom: 1px solid #111827;
  }

  tbody tr:last-child td { border-bottom: none; }

  tbody tr:hover td { background: rgba(255,255,255,0.02); }

  .positive { color: #4ade80; font-weight: 500; }
  .negative { color: #f87171; font-weight: 500; }
  .neutral  { color: #6b7280; }

  /* PE CARDS */
  .pe-cards {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
  }

  .pe-card {
    background: #111827;
    border: 1px solid #1f2937;
    border-radius: 12px;
    padding: 24px 20px;
    text-align: center;
  }

  .pe-period {
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: #4b5563;
    margin-bottom: 12px;
  }

  .pe-value {
    font-family: 'DM Serif Display', serif;
    font-size: 36px;
    color: #e8eaf0;
  }

  /* FOOTER NOTE */
  .footer-note {
    text-align: center;
    margin-top: 32px;
    font-size: 12px;
    color: #374151;
  }

  @media (max-width: 768px) {
    .stat-cards { grid-template-columns: repeat(2, 1fr); }
    .pe-cards { grid-template-columns: repeat(3, 1fr); }
    .company-header { flex-direction: column; gap: 16px; }
    .search-box { flex-direction: column; }
    .header h1 { font-size: 30px; }
  }
`;

function GrowthCell({ value }) {
  if (!value || value === '—' || value === 'N/A') return <td className="neutral">{value || 'N/A'}</td>;
  const isPositive = !value.startsWith('-');
  return <td className={isPositive ? 'positive' : 'negative'}>{isPositive ? '▲ ' : '▼ '}{value}</td>;
}

export default function App() {
  const [symbol, setSymbol] = useState('');
  const [stockData, setStockData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSearch = async () => {
    if (!symbol.trim()) return;
    setLoading(true);
    setError('');
    setStockData(null);
    try {
      const res = await axios.get(`/api/stock/${symbol.trim().toUpperCase()}`);
      setStockData(res.data);
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to fetch data. Please check the symbol (e.g. TATASTEEL, INFY, RELIANCE)');
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSearch();
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app">

        {/* HEADER */}
        <div className="header">
          <div className="header-tag">Stock Research</div>
          <h1>Analyst <span>Report</span></h1>
          <p>Enter an NSE/BSE symbol to generate a clean 1-pager</p>
        </div>

        {/* SEARCH */}
        <div className="search-box">
          <span className="search-label">Symbol</span>
          <input
            className="search-input"
            type="text"
            placeholder="e.g. TATASTEEL, INFY, RELIANCE, HDFCBANK"
            value={symbol}
            onChange={e => setSymbol(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <button className="search-btn" onClick={handleSearch} disabled={loading || !symbol.trim()}>
            {loading ? 'Fetching...' : 'Analyze →'}
          </button>
        </div>

        {/* ERROR */}
        {error && <div className="error-box">⚠ {error}</div>}

        {/* LOADING */}
        {loading && (
          <div className="loading">
            <div className="spinner" />
            <p>Fetching data from screener.in...</p>
          </div>
        )}

        {/* REPORT */}
        {stockData && !loading && (
          <>
            {/* Company Header */}
            <div className="company-header">
              <div>
                <div className="company-name">{stockData.companyName || stockData.symbol}</div>
                <div className="company-symbol">NSE: {stockData.symbol}</div>
              </div>
              <div className="cmp-badge">
                <div className="cmp-label">Current Price</div>
                <div className="cmp-value">₹{stockData.cmp || '—'}</div>
              </div>
            </div>

            {/* TABLE 1 — Key Ratios */}
            <div className="section">
              <div className="section-title">Key Metrics</div>
              <div className="stat-cards">
                <div className="stat-card">
                  <div className="stat-label">P/E Ratio</div>
                  <div className="stat-value">{stockData.pe || '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Market Cap</div>
                  <div className="stat-value">{stockData.marketCap ? `₹${stockData.marketCap}` : '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Dividend Yield</div>
                  <div className="stat-value">{stockData.dividendYield || '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Book Value</div>
                  <div className="stat-value">{stockData.bookValue ? `₹${stockData.bookValue}` : '—'}</div>
                </div>
              </div>
            </div>

            {/* TABLE 2 — Financial History */}
            <div className="section">
              <div className="section-title">Financial History (Last 3 Years)</div>
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Year</th>
                      <th>Revenue (Cr)</th>
                      <th>Revenue Growth</th>
                      <th>Net Profit (Cr)</th>
                      <th>Profit Growth</th>
                      <th>Net Margin</th>
                    </tr>
                  </thead>
                  <tbody>
                    {stockData.financials && stockData.financials.length > 0 ? (
                      stockData.financials.map((f, i) => (
                        <tr key={i}>
                          <td style={{ fontWeight: 600, color: '#e8eaf0' }}>{f.year}</td>
                          <td>{f.revenue}</td>
                          <GrowthCell value={f.revenueGrowth} />
                          <td>{f.profit}</td>
                          <GrowthCell value={f.profitGrowth} />
                          <td>{f.netProfitMargin}</td>
                        </tr>
                      ))
                    ) : (
                      <tr><td colSpan={6} className="neutral" style={{ textAlign: 'center', padding: '24px' }}>No financial data found</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>

            {/* TABLE 3 — Median PE */}
            <div className="section">
              <div className="section-title">Median P/E Analysis</div>
              <div className="pe-cards">
                <div className="pe-card">
                  <div className="pe-period">1 Year</div>
                  <div className="pe-value">{stockData.medianPe1Year || '—'}</div>
                </div>
                <div className="pe-card">
                  <div className="pe-period">3 Year</div>
                  <div className="pe-value">{stockData.medianPe3Year || '—'}</div>
                </div>
                <div className="pe-card">
                  <div className="pe-period">5 Year</div>
                  <div className="pe-value">{stockData.medianPe5Year || '—'}</div>
                </div>
              </div>
            </div>

            {/* Concall placeholder */}
            <div className="section">
              <div className="section-title">Concall Analysis</div>
              <div className="table-wrap" style={{ padding: '32px', textAlign: 'center' }}>
                <div style={{ fontSize: '28px', marginBottom: '12px' }}>🎙</div>
                <div style={{ color: '#6b7280', fontSize: '14px', marginBottom: '8px' }}>
                  AI-powered concall analysis coming soon
                </div>
                <div style={{ color: '#374151', fontSize: '12px' }}>
                  Will include: Growth plans · Capex · JV · Key Q&A from latest concall
                </div>
              </div>
            </div>

            <div className="footer-note">
              Data sourced from screener.in · For research purposes only · Not investment advice
            </div>
          </>
        )}
      </div>
    </>
  );
}
